const b = $input.first().json.body || $input.first().json;
const agentType = b.agent_type || 'standard';
const agentPrompt = b.agent_prompt || '';
const runLabel = b.run_label || ('Test Run ' + new Date().toLocaleDateString('en-GB'));
const runId = 'run_' + Date.now();
const filterGroups = b.groups || ['all'];
return [{ json: { runId, agentType, agentPrompt, runLabel, filterGroups, startedAt: new Date().toISOString() } }];

const run = $('n-init').first().json;
const raw = $input.first().json;
let scenarios = Array.isArray(raw) ? raw : JSON.parse(raw);
// Filter premium-only scenarios
if (run.agentType === 'standard') {
  scenarios = scenarios.filter(s => !s.premiumOnly);
}
// Filter by groups if specified
if (run.filterGroups && !run.filterGroups.includes('all')) {
  scenarios = scenarios.filter(s => run.filterGroups.includes(s.group));
}
// Return as array items for batch processing
return scenarios.map(s => ({ json: { ...run, scenario: s } }));

const evalRaw = $('n-evaluate').first().json.content[0].text;
let evaluation;
try {
  const clean = evalRaw.replace(/```json|```/g, '').trim();
  evaluation = JSON.parse(clean);
} catch(e) {
  evaluation = { pass: false, score: 0, severity: 'HIGH', issues: ['Evaluator parse error'], fix_needed: 'Check evaluator response', root_cause: 'Parse error' };
}
const item = $json;
return [{ json: {
  run_id: item.runId,
  agent_type: item.agentType,
  run_label: item.runLabel,
  scenario_id: item.scenario.id,
  scenario_name: item.scenario.name,
  scenario_group: item.scenario.group,
  pass: evaluation.pass,
  score: evaluation.score,
  severity: evaluation.severity,
  issues: JSON.stringify(evaluation.issues || []),
  fix_needed: evaluation.fix_needed || '',
  root_cause: evaluation.root_cause || '',
  caller_turn1: $('n-simulate-caller').first().json.choices[0].message.content,
  agent_turn1: $('n-agent-response').first().json.content[0].text,
  caller_turn2: $('n-groq-turn2').first().json.choices[0].message.content,
  agent_turn2: $('n-agent-turn2').first().json.content[0].text,
  tested_at: new Date().toISOString()
} }];
